@namespace Lumeo
@implements IAsyncDisposable

@*
    PullToRefresh — iOS/Android-style pull-down-to-refresh primitive.

    The wrapper IS the scroll container: it sets `overflow-y: auto` on the
    root <div>, which lets us read scrollTop directly via JS interop. We only
    "engage" the pull gesture when the container is at scrollTop == 0; once
    engaged, we apply a rubber-band translateY (capped at MaxPullPx) and
    fade in a Lucide.RefreshCw spinner above the content. On release:
    - delta >= ThresholdPx -> invoke OnRefresh, hold the spinner visible
      until the handler completes, then animate back to 0.
    - delta <  ThresholdPx -> animate back to 0 without firing.

    v1 simplification: requires the wrapper itself to be the scroll container
    (overflow-y: auto baked into the root class). v2 could traverse to the
    first scrollable ancestor.
*@

<div id="@EffectiveId"
     class="@CssClass"
     style="@ContainerStyle"
     @ref="_ref"
     @onpointerdown="HandlePointerDown"
     @onpointermove="HandlePointerMove"
     @onpointerup="HandlePointerUp"
     @onpointercancel="HandlePointerUp"
     @attributes="AdditionalAttributes">
    <div class="pointer-events-none absolute inset-x-0 top-0 flex justify-center"
         style="@SpinnerStyle">
        <div class="flex h-10 w-10 items-center justify-center rounded-full bg-background text-foreground shadow-md ring-1 ring-border">
            <Blazicon Svg="Lucide.RefreshCw" class="@SpinnerIconClass" />
        </div>
    </div>
    <div style="@ContentStyle">
        @ChildContent
    </div>
</div>

@inject IComponentInteropService Interop

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public EventCallback OnRefresh { get; set; }
    [Parameter] public double ThresholdPx { get; set; } = 80;
    [Parameter] public double MaxPullPx { get; set; } = 120;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _elementId = LumeoIds.New("ptr");
    private ElementReference _ref;
    private bool _gestureGuardRegistered;

    // When a consumer splats an `id="..."` via AdditionalAttributes it wins in
    // the rendered DOM (the splat is emitted after the explicit id). All JS
    // interop must target that same id, otherwise every getElementById lookup
    // (gesture guard, scrollTop gate, pointer capture) silently no-ops.
    // Mirror Carousel.razor's EffectiveRootId pattern.
    private string EffectiveId => LumeoIds.Effective(AdditionalAttributes, _elementId);

    private long? _activePointerId;
    private double _startY;
    private double _currentDelta;
    private bool _engaged;
    private bool _refreshing;
    // While `_refreshing` we lock the spinner at the threshold position so
    // the user sees a stable indicator until OnRefresh completes.
    private double LockedOffset => _refreshing ? ThresholdPx : 0;

    private string CssClass =>
        Cx.Merge("relative h-full w-full overflow-y-auto overflow-x-hidden overscroll-y-contain bg-background text-foreground", Class);

    // Transitions:
    // - During an active drag we set transform without a transition so it
    //   tracks the finger 1:1.
    // - On release (and during the refresh lock) we apply a short ease
    //   transition so the rubber-band snap feels natural.
    private string TransitionStyle => _activePointerId.HasValue
        ? "transition: none;"
        : "transition: transform 200ms ease-out;";

    private double VisualOffset
    {
        get
        {
            if (_refreshing) return LockedOffset;
            if (!_engaged) return 0;
            // Rubber-band: halve the delta and clamp to MaxPullPx.
            var raw = Math.Max(0, _currentDelta) * 0.5;
            return Math.Min(raw, MaxPullPx);
        }
    }

    private string ContentStyle =>
        $"transform: translateY({VisualOffset.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture)}px); {TransitionStyle} will-change: transform;";

    private string SpinnerStyle
    {
        get
        {
            var off = VisualOffset;
            // Fade opacity proportional to threshold progress; cap at 1.
            var progress = ThresholdPx > 0 ? Math.Min(1.0, off / ThresholdPx) : 0;
            // Position the spinner just above the content, slid in alongside.
            var translate = off - 40; // -40 to start just above the top edge
            return $"transform: translateY({translate.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture)}px); " +
                   $"opacity: {progress.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture)}; " +
                   $"{TransitionStyle} will-change: transform, opacity;";
        }
    }

    private string SpinnerIconClass => (_refreshing ? "h-5 w-5 animate-spin" : "h-5 w-5").Trim();

    // pan-y still lets the container scroll natively everywhere EXCEPT a
    // downward drag pinned at the top — that case is claimed by the non-passive
    // touchmove guard registered in OnAfterRenderAsync (#308). Without the guard
    // the browser consumed the top-pull as overscroll and our pointer deltas
    // never moved the rubber-band.
    private string ContainerStyle => "touch-action: pan-y;";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender || _gestureGuardRegistered) return;
        try
        {
            await Interop.RegisterPullToRefresh(EffectiveId);
            _gestureGuardRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    private async Task HandlePointerDown(PointerEventArgs e)
    {
        // Accept all pointer types (touch, mouse, pen) so Chrome DevTools mobile
        // emulation works — DevTools emulation dispatches pointer events with
        // pointerType "mouse" even when simulating a touch device.
        if (_refreshing) return;
        if (_activePointerId.HasValue) return;

        // Gate on scrollTop == 0; if the container is scrolled, let the native
        // scroll handle the pointer instead of engaging the pull.
        double scrollTop = 0;
        try { scrollTop = await Interop.GetScrollTop(EffectiveId); }
        catch (JSDisconnectedException) { return; }
        if (scrollTop > 0) return;

        _activePointerId = e.PointerId;
        _startY = e.ClientY;
        _currentDelta = 0;
        _engaged = false;

        // Capture the pointer so pointermove continues to fire even when the
        // pointer leaves the element boundary. This is the key fix for Chrome
        // DevTools mobile emulation where without capture the move events stop.
        try { await Interop.SetPointerCaptureOnElement(EffectiveId, e.PointerId); }
        catch (JSDisconnectedException) { return; }
    }

    private void HandlePointerMove(PointerEventArgs e)
    {
        if (!_activePointerId.HasValue || _activePointerId.Value != e.PointerId) return;
        if (_refreshing) return;

        var delta = e.ClientY - _startY;
        if (delta <= 0)
        {
            // Released the pull (or moving upward) — disengage but keep
            // pointer captured so a subsequent downward move can re-engage.
            _currentDelta = 0;
            if (_engaged)
            {
                _engaged = false;
                StateHasChanged();
            }
            return;
        }

        _engaged = true;
        _currentDelta = delta;
        StateHasChanged();
    }

    private async Task HandlePointerUp(PointerEventArgs e)
    {
        if (!_activePointerId.HasValue || _activePointerId.Value != e.PointerId) return;

        var wasEngaged = _engaged;
        var finalDelta = _currentDelta;

        _activePointerId = null;
        _engaged = false;
        _currentDelta = 0;

        // Release the pointer capture acquired in HandlePointerDown.
        try { await Interop.ReleasePointerCaptureOnElement(EffectiveId, e.PointerId); }
        catch (JSDisconnectedException) { /* already gone */ }
        catch { /* ignore if capture was already released by the browser */ }

        // Effective pulled distance is the visual offset (post-rubber-band).
        var pulled = Math.Min(Math.Max(0, finalDelta) * 0.5, MaxPullPx);

        if (wasEngaged && pulled >= ThresholdPx && !_refreshing)
        {
            _refreshing = true;
            StateHasChanged();
            try
            {
                await OnRefresh.InvokeAsync();
            }
            finally
            {
                _refreshing = false;
                StateHasChanged();
            }
        }
        else
        {
            StateHasChanged();
        }
    }

    public async ValueTask DisposeAsync()
    {
        // Tear down the non-passive touchmove guard registered on first render.
        if (_gestureGuardRegistered)
        {
            try { await Interop.UnregisterPullToRefresh(EffectiveId); }
            catch (JSDisconnectedException) { }
            catch (InvalidOperationException) { } // also covers ObjectDisposedException (a subtype) at shutdown
        }
    }
}
